solution_code:
#include <iostream>

using TransformFn = int (*)(int);

int square(int x) { return x * x; }
int absolute(int x) { return (x >= 0) ? x : -x; }

int transformAndSum(const int arr[], int size, TransformFn transform)
{
    int total{ 0 };
    for (int i{ 0 }; i < size; ++i)
        total += transform(arr[i]);
    return total;
}

int main()
{
    int n{};
    std::cin >> n;

    int arr[100]{};
    for (int i{ 0 }; i < n; ++i)
        std::cin >> arr[i];

    std::cout << transformAndSum(arr, n, square) << '\n';
    std::cout << transformAndSum(arr, n, absolute) << '\n';

    return 0;
}
